def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                temp_sum = 0
                for b in range(1, a * 2):
                    val = ((ratio - a) ** 4) / (a * b + 1)
                    trig = np.cos(ratio * b / (a + 0.5)) * np.sin(ratio / (b + 1))
                    temp_sum += val * trig
                priority += np.tanh(temp_sum) * 12
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 2.2
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                block_sum = 0
                for q in range(1, p + 4):
                    exp_term = np.exp(-(ratio - p) ** 2 / (q + 1))
                    block_sum += np.tanh(exp_term * np.sin(ratio * q))
                priority += block_sum * 1.8
            priority -= np.sqrt(ratio) * 7 + np.cos(ratio * 2) * 3
        elif 2 <= ratio <= 5:
            series1 = 0
            for s in range(1, 20):
                series1 += ((ratio - 2) ** s) / (s + 0.3) * np.sin(s * ratio) * np.cos(s * ratio / 2)
            priority = series1 - np.log(ratio + 1) * 8 + np.tanh(3.5 - ratio) * 2.3
            if bin_cap < item * 2:
                priority += np.exp(-bin_cap / (item + 0.1)) * 4
        elif 1 <= ratio < 2:
            accum = 0
            for n in range(1, 15):
                val = ((2 - ratio) ** n) / (n ** 1.5 + 0.1) * np.cos(n * 1.5 * ratio)
                accum += val
            penalty = np.sqrt(item * bin_cap) / (bin_cap + 1)
            priority = accum + penalty * 6 + np.sin(10 * ratio) * 2
            for m in range(1, 6):
                priority += np.cos(m * ratio * i) * ((ratio - 1) ** m) / (m + 1)
        elif 0.4 <= ratio < 1:
            temp = 0
            for x in range(1, 12):
                temp += ((1 - ratio) ** x) / (x * 2) * np.sin(x * item)
            if int(item * 2.5 + i) % 5 == 0:
                temp *= np.log1p(bin_cap + 2) * 1.1
            else:
                temp /= (np.sqrt(bin_cap + 2) + 1)
            priority = temp + np.exp(-ratio) * 1.7
            for y in range(1, 8):
                priority += ((1 - ratio) ** y) * np.sin(y * item * 0.9) / (y + 1)
        elif 0.1 <= ratio < 0.4:
            summ = 0
            for z in range(1, 20):
                summ += ((0.4 - ratio) ** z) / (z * 2.3) * np.cos(z * ratio * 3)
            priority = summ + 2 / (bin_cap + 2.5)
            if (int(item * 3.1) + i) % 7 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6.3
            else:
                priority -= np.exp(-ratio * 2.5) * 3.7
        else:
            residual = 0
            for w in range(1, 15):
                residual += ((0.1 - ratio) ** w) / (w * 5) * np.sin(w * item * 0.85)
            priority = residual + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 2.6
            else:
                priority /= 2.6
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7.2
            else:
                priority -= np.exp(-ratio * 3) * 5
            for v in range(1, 9):
                priority += ((0.1 - ratio) ** v) / (v * 9) * np.cos(item * v * 0.95)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.1
        modification = 0
        for offset in range(1, 6):
            if (i + offset) % 4 == 0:
                modification += np.sin(ratio * (i + offset) * 1.2) * 0.5
            else:
                modification -= np.cos(ratio * (i + offset) * 1.2) * 0.5
        if i % 4 == 0:
            modification += np.sin(ratio * i * 1.3) * 0.7
        else:
            modification -= np.cos(ratio * i * 1.3) * 0.7
        priority += modification
        if priority < -100:
            priority = -100 + np.tanh(priority + 100) * 20
        elif priority > 100:
            priority = 100 + np.tanh(priority - 100) * 20
        priorities[i] = priority
    return priorities
